import{_ as a,c as e,o as p,a4 as r}from"./chunks/framework.CzsDe1xi.js";const q=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/个人/面试/面试经历.md","filePath":"packages/doc/src/个人/面试/面试经历.md","lastUpdated":1707061484000}'),s={name:"doc/个人/面试/面试经历.md"},t=r('<h2 id="_1-字节lark部门面试-卒" tabindex="-1">1.字节Lark部门面试（卒） <a class="header-anchor" href="#_1-字节lark部门面试-卒" aria-label="Permalink to &quot;1.字节Lark部门面试（卒）&quot;">​</a></h2><p>一面</p><p>1.自我介绍</p><p><s>2.项目难点，亮点，学习到了什么，统计模块，问了单词本怎么更新的问题（就是一张表）</s></p><p><s>3.Mysql的B树，B+树，索引怎么建，失效，事务隔离级别，</s></p><p><s>4.tcp的拥塞控制，窗口滑动机制</s></p><p><s>5.限流算法</s></p><p><s>6.一道算法题</s></p><h2 id="_2-百度物联网网部门-go研发工程师" tabindex="-1">2.百度物联网网部门-GO研发工程师 <a class="header-anchor" href="#_2-百度物联网网部门-go研发工程师" aria-label="Permalink to &quot;2.百度物联网网部门-GO研发工程师&quot;">​</a></h2><h4 id="一面" tabindex="-1">一面 <a class="header-anchor" href="#一面" aria-label="Permalink to &quot;一面&quot;">​</a></h4><p>​ 1.自我介绍</p><p>2.问项目（统计模块，问200个字段怎么动态删减）</p><p>3.sql,索引优化</p><p>4.go的调度原理</p><p>5.docker了解吗？</p><p>6.一道sql题</p><p>一张lesson表，有student(学生名)、class(课程)字段，查找lesson表中学生A和学生B共同选的课程</p><ol><li>select class from lesson where class in (select class from less where student = A</li></ol><p>) and class in (select class from less where student = B</p><p>)</p><ol start="2"><li>select class from lesson as a left join lesson as b on a.class=b.class where a.student = A and b.student = B</li></ol><p>7.一道算法题</p><p>给定一个整数数组，编写一个函数，找出索引m和n，只要将索引区间[m,n]的元素排好序，整个数组就是有序的。注意：n-m尽量最小，也就是说，找出符合条件的最短序列。函数返回值为[m,n]，若不存在这样的m和n（例如整个数组是有序的），请返回[-1,-1]。</p><p>示例：</p><p>输入： [1,2,4,7,10,11,7,12,6,7,16,18,19]</p><p>输出： [3,9]</p><p>func subSort(array []int) []int {</p><p>}</p><h4 id="二面-卒-女面试官-一看就不是正经找人的-嘻嘻哈哈的" tabindex="-1">二面：卒（女面试官，一看就不是正经找人的，嘻嘻哈哈的） <a class="header-anchor" href="#二面-卒-女面试官-一看就不是正经找人的-嘻嘻哈哈的" aria-label="Permalink to &quot;二面：卒（女面试官，一看就不是正经找人的，嘻嘻哈哈的）&quot;">​</a></h4><p>​ 1.自我介绍，项目</p><p>​ 2.mysql 的悲观锁使用场景</p><p>3.go channel底层实现</p><ol start="4"><li><p>GMP调度模型</p></li><li><p>快排</p></li></ol><h2 id="_3-度小满金融-不知道问点啥-感觉不合适" tabindex="-1">3.度小满金融（不知道问点啥，感觉不合适） <a class="header-anchor" href="#_3-度小满金融-不知道问点啥-感觉不合适" aria-label="Permalink to &quot;3.度小满金融（不知道问点啥，感觉不合适）&quot;">​</a></h2><h4 id="一面-1" tabindex="-1">一面： <a class="header-anchor" href="#一面-1" aria-label="Permalink to &quot;一面：&quot;">​</a></h4><p>自我介绍</p><p>mysql各个版本的特性,qps,不同存储引擎特性</p><p>php各个版本的特性</p><p>go的channel,array,slice,map等基础知识</p><p>redis雪崩，热点key怎么优化</p><p>redis数据类型，qps</p><p>问了问APP端接口耗时</p><p>http状态码301，403，419？</p><p>git操作命令</p><p>linux操作命令，统计数字</p><p>一道mid算法题</p><h2 id="_4-抖音安全面试" tabindex="-1">4.抖音安全面试 <a class="header-anchor" href="#_4-抖音安全面试" aria-label="Permalink to &quot;4.抖音安全面试&quot;">​</a></h2><h4 id="一面-2" tabindex="-1">一面： <a class="header-anchor" href="#一面-2" aria-label="Permalink to &quot;一面：&quot;">​</a></h4><p>​ 自我介绍</p><p>​ 项目经历</p><p>​ 1.聚簇索引和非聚簇索引的区别？</p><p>​ 2.B+树</p><p>​ 3.索引失效的情况，为什么加索引</p><p>​ 4.go的数据类型，new make的区别，map扩容机制，协程，进程，线程的区别</p><p>5.算法，括号</p><p>6.mysql的主从，redis的持久化机制</p><p>7.三次握手，突然客户端断开了以后链接怎么办？</p><h4 id="二面" tabindex="-1">二面： <a class="header-anchor" href="#二面" aria-label="Permalink to &quot;二面：&quot;">​</a></h4><p>​ 自我介绍</p><p>​ 项目经历</p><p>1.数据库八股文</p><p>2.redis八股文</p><p>3.2道算法，不会做，卒</p><p>一道动态规划，一道双指针，mid难度</p><h2 id="_5-途为新能-创业公司-待遇挺高-挑战也大" tabindex="-1">5.途为新能（创业公司，待遇挺高，挑战也大） <a class="header-anchor" href="#_5-途为新能-创业公司-待遇挺高-挑战也大" aria-label="Permalink to &quot;5.途为新能（创业公司，待遇挺高，挑战也大）&quot;">​</a></h2><p>2面技术+2面HR</p><p>1.力扣33题，数组某个点翻转，二分查找target</p><p>2.归并排序，多路归并排序</p><h2 id="_6-好好住" tabindex="-1">6.好好住 <a class="header-anchor" href="#_6-好好住" aria-label="Permalink to &quot;6.好好住&quot;">​</a></h2><h4 id="一面-40min" tabindex="-1">一面(40min) <a class="header-anchor" href="#一面-40min" aria-label="Permalink to &quot;一面(40min)&quot;">​</a></h4><p>快排算法，redis的延迟队列，多协程打印奇数偶数，问项目，数据库索引（死锁如何解决，幻读，脏读等），CPU多行缓存读取，进程线程协程区别？</p><h4 id="二面-30min" tabindex="-1">二面（30min） <a class="header-anchor" href="#二面-30min" aria-label="Permalink to &quot;二面（30min）&quot;">​</a></h4><p>redis相关，消息队列，场景题目设计等，项目</p><p>问redis问的比较多，延迟队列的设计，包括分布式session的存取等问题，还有持久化的原理</p><h4 id="hr面-1小时多" tabindex="-1">HR面（1小时多） <a class="header-anchor" href="#hr面-1小时多" aria-label="Permalink to &quot;HR面（1小时多）&quot;">​</a></h4><p>离职原因，人数等问题</p><h2 id="_7-考呀呀-待遇不好-要啥没啥-不考虑" tabindex="-1">7.考呀呀（待遇不好，要啥没啥，不考虑） <a class="header-anchor" href="#_7-考呀呀-待遇不好-要啥没啥-不考虑" aria-label="Permalink to &quot;7.考呀呀（待遇不好，要啥没啥，不考虑）&quot;">​</a></h2><h4 id="一面负责人" tabindex="-1">一面负责人 <a class="header-anchor" href="#一面负责人" aria-label="Permalink to &quot;一面负责人&quot;">​</a></h4><p>常用算法，数据结构等项目</p><h4 id="二面boss" tabindex="-1">二面Boss <a class="header-anchor" href="#二面boss" aria-label="Permalink to &quot;二面Boss&quot;">​</a></h4><p>开放式聊天</p><h4 id="三面现场" tabindex="-1">三面现场 <a class="header-anchor" href="#三面现场" aria-label="Permalink to &quot;三面现场&quot;">​</a></h4><p>HR面</p><h2 id="_8-搜狐" tabindex="-1">8.搜狐 <a class="header-anchor" href="#_8-搜狐" aria-label="Permalink to &quot;8.搜狐&quot;">​</a></h2><h4 id="一面-3" tabindex="-1">一面 <a class="header-anchor" href="#一面-3" aria-label="Permalink to &quot;一面&quot;">​</a></h4><p>几乎都是go的语法题，xss,http code码等</p><p>不会的问题：</p><p>1.struct tag没指定的时候，json序列化之后就是原字段</p><p>2.nil不能用*再修饰赋值</p><p>3.xss回答的不够详细，笼统</p><h4 id="二面-不到半个小时" tabindex="-1">二面（不到半个小时） <a class="header-anchor" href="#二面-不到半个小时" aria-label="Permalink to &quot;二面（不到半个小时）&quot;">​</a></h4><p>1.力扣260原题，不会做</p><p>2.问了一些go的概念，没啥问题</p><p>3.问了一个空接口的概念，蒙了</p><p>4.问了问docker,k8s等问题，比较开放</p><h4 id="hr面试-卒" tabindex="-1">HR面试（卒） <a class="header-anchor" href="#hr面试-卒" aria-label="Permalink to &quot;HR面试（卒）&quot;">​</a></h4><p>聊了半个小时左右</p>',97),o=[t];function l(i,h,n,d,c,u){return p(),e("div",null,o)}const b=a(s,[["render",l]]);export{q as __pageData,b as default};
